  flashcards: [
    { front: "What is a force, and what unit is it measured in?", back: "A push or a pull, measured in newtons (N) using a newtonmeter." },
    { front: "Name three things a force can do.", back: "Change an object's speed (speed up or slow down), change its direction, or change its shape." },
    { front: "Contact vs non-contact force?", back: "Contact forces need touching (friction, drag, tension, normal); non-contact forces act at a distance (gravity, magnetism, electrostatic)." },
    { front: "What is the resultant force?", back: "The single overall force found by adding all the forces on an object, taking direction into account." },
    { front: "What do balanced forces do?", back: "Resultant is zero: a still object stays still and a moving object keeps a constant speed in a straight line." },
    { front: "What do unbalanced forces do?", back: "They give a resultant force that speeds up, slows down or changes the direction of an object." },
    { front: "Difference between mass and weight?", back: "Mass is the amount of matter in kg (unchanging); weight is the force of gravity in N (changes with g)." },
    { front: "What is the weight equation?", back: "Weight = mass x gravitational field strength (W = m x g); g is about 10 N/kg on Earth." },
    { front: "Which way do friction and drag act?", back: "Always opposite to the direction of motion; drag increases with speed." },
    { front: "What is the speed equation and its unit?", back: "Speed = distance / time, measured in metres per second (m/s)." },
    { front: "What does a flat line on a distance-time graph mean?", back: "The object is stationary (its distance is not changing)." },
    { front: "State Hooke's law.", back: "The extension of a spring is proportional to the force applied, up to the elastic limit." },
    { front: "What is a moment (turning effect)?", back: "Moment = force x distance from the pivot; a bigger force or distance turns more easily." },
    { front: "What is the pressure equation and its unit?", back: "Pressure = force / area, measured in N/m^2 (pascals, Pa)." },
  ],

